fun main() {
    val greet = { name: String -> "Hello, $name!" }
    println(greet("Alice"))

    val nums = listOf(1, 2, 3, 4, 5)
    val evens = nums.filter { it % 2 == 0 }
    val doubled = nums.map { it * 2 }
    println("Evens: $evens")
    println("Doubled: $doubled")

    // Trailing lambda
    val result = nums.fold(0) { acc, i -> acc + i }
    println("Sum: $result")
}
